use std::fs::{File, OpenOptions};
use std::io::{self, Write, Read, Seek, Cursor};
use std::mem::MaybeUninit;

struct MappedData {
    data: Vec<u8>,
}

impl MappedData {
    fn new(size: usize) -> io::Result<Self> {
        let file = OpenOptions::new().read(true).write(true).create(true).open("temp_mapped.bin")?;
        let mut file = File::from(file);

        if size > 0 {
            file.write_all(&vec![0; size])?;
        }

        Ok(MappedData { data: vec![0; size] })
    }

    fn map_and_read(&mut self, offset: usize, length: usize) -> io::Result<Vec<u8>> {
        let file = OpenOptions::new().read(true).open("temp_mapped.bin")?;
        let mut reader = io::BufReader::with_capacity(4096, file);

        reader.seek(io::SeekFrom::Start(offset as u64))?;
        let mut buffer = vec![0; length];
        reader.read(&mut buffer)?; 
        Ok(buffer)
    }

    fn cleanup() {
        if let Err(e) = std::fs::remove_file("temp_mapped.bin") {
            eprintln!("Cleanup failed: {}", e);
        }
    }
}

fn main() -> io::Result<()> {
    let mut data_storage = MappedData::new(1024)?;
    data_storage.map_and_read(0, 5)?; 
    data_storage.map_and_read(512, 10)?; 

    MappedData::cleanup();
    Ok(())
}

